<span class="line"><span style="color:#F92672;">        return</span><span style="color:#F8F8F2;">(fibona(n</span><span style="color:#F92672;">-</span><span style="color:#AE81FF;">1</span><span style="color:#F8F8F2;">)</span><span style="color:#F92672;">+</span><span style="color:#F8F8F2;">_____(</span><span style="color:#AE81FF;">1</span><span style="color:#F8F8F2;">)_____)</span></span>
