<span class="line"><span style="color:#F8F8F2;">K</span><span style="color:#F92672;">=</span><span style="color:#66D9EF;">abs</span><span style="color:#F8F8F2;">(</span><span style="color:#66D9EF;">eval</span><span style="color:#F8F8F2;">(</span><span style="color:#66D9EF;">input</span><span style="color:#F8F8F2;">()))</span></span>
